 1	import * as React from 'react';
 2	import { Tooltip, TooltipPosition } from '@patternfly/react-core';
 3	import { icons, serverConfig } from '../../config';
 4	import { KialiIcon } from '../../config/KialiIcon';
 5	import { PFBadge } from '../Pf/PfBadges';
 6	import { infoStyle } from 'styles/IconStyle';
 7	
 8	type MissingLabelProps = {
 9	  className?: string;
10	  missingApp: boolean;
11	  missingVersion: boolean;
12	  tooltip: boolean;
13	};
14	
15	export const MissingLabel: React.FC<MissingLabelProps> = (props: MissingLabelProps) => {
16	  const appLabelName = serverConfig.istioLabels.appLabelName || 'app'; // just need a value for badge text
17	  const versionLabelName = serverConfig.istioLabels.versionLabelName || 'version'; // just need a value for badge text
18	  const icon = icons.istio.missingLabel.icon;
19	  const color = icons.istio.missingLabel.color;
20	
21	  const tooltipContent = (
22	    <div style={{ textAlign: 'left' }}>
23	      {props.missingApp && (
24	        <>
25	          <div>
26	            <PFBadge badge={{ badge: appLabelName }} isRead={true} style={{ marginRight: 0 }} /> label is missing.{' '}
27	            <br />
28	          </div>
29	          <div>This workload won't be linked with an application.</div>
30	        </>
31	      )}
32	
33	      {props.missingVersion && (
34	        <>
35	          <div>
36	            <PFBadge badge={{ badge: versionLabelName }} isRead={true} style={{ marginRight: 0 }} /> label is missing.{' '}
37	            <br />
38	          </div>
39	          <div>The label is recommended as it affects telemetry.</div>
40	        </>
41	      )}
42	
43	      <div>Missing labels may impact telemetry reported by the Istio proxy.</div>
44	    </div>
45	  );
46	
47	  const iconComponent = (
48	    <span className={props.className}>
49	      {React.createElement(icon, { style: { color: color } })}
50	
51	      {!props.tooltip && (
52	        <span style={{ marginLeft: '0.5rem' }}>
53	          Missing {props.missingApp ? 'App' : props.missingVersion ? 'Version' : 'Label'}
54	          <Tooltip key="tooltip_missing_label" position={TooltipPosition.top} content={tooltipContent}>
55	            <KialiIcon.Info className={infoStyle} />
56	          </Tooltip>
57	        </span>
58	      )}
59	    </span>
60	  );
61	
62	  return props.tooltip ? (
63	    <Tooltip key="tooltip_missing_label" position={TooltipPosition.right} content={tooltipContent}>
64	      {iconComponent}
65	    </Tooltip>
66	  ) : (
67	    iconComponent
68	  );
69	};

